import{_ as s,o as e,c as n,a2 as i}from"./chunks/framework.4hJCcvDE.js";const k=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"blog/知识点_006-ECS并行安全的工程实践.md","filePath":"blog/知识点_006-ECS并行安全的工程实践.md","lastUpdated":1784835052000}'),l={name:"blog/知识点_006-ECS并行安全的工程实践.md"};function t(p,a,r,h,o,d){return e(),n("div",null,[...a[0]||(a[0]=[i(`<h2 id="引言" tabindex="-1">引言 <a class="header-anchor" href="#引言" aria-label="Permalink to &quot;引言&quot;">​</a></h2><p>在 BattleSystem-ECS 项目中，为了实现 10K 敌人 + 20+ 系统并行运行、帧率超 3000 FPS，所有系统内部都用 <code>Parallel.For</code> 批处理。但引入并行后第一个踩到的坑就是：多个攻击系统同时写同一个敌人的血量，数据竞争导致伤害丢失。</p><p>这篇文章总结一套在 ECS 并行环境下验证过的安全模式——&quot;两阶段模式&quot;（并行收集 + 串行 apply），并附带几个具体踩坑案例。</p><h2 id="一、问题的本质-并行写共享状态" tabindex="-1">一、问题的本质：并行写共享状态 <a class="header-anchor" href="#一、问题的本质-并行写共享状态" aria-label="Permalink to &quot;一、问题的本质：并行写共享状态&quot;">​</a></h2><p>先看一个朴素的塔防攻击流程：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>PlayerTowerAttack.Update()  → 遍历玩家攻击范围内的敌人 → enemyHealth -= damage → 检查是否需要销毁</span></span>
<span class="line"><span>TowerAttack.Update()        → 遍历塔攻击范围内的敌人    → enemyHealth -= damage → 检查是否需要销毁</span></span>
<span class="line"><span>SkillSystem.Update()        → 遍历技能范围内的敌人      → enemyHealth -= damage → 检查是否需要销毁</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>三个系统在 <code>Parallel.For</code> 里各自并行执行。假设玩家和塔同时打中同一个敌人，代码可能是这样的：</p><div class="language-csharp vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">csharp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// PlayerTowerAttack 线程 A</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">float</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> newHealth</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> enemyHealth[enemyId] </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> damage1;  </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 读到 50</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">enemyHealth[enemyId] </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> newHealth;                   </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 准备写 30</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// TowerAttack 线程 B 恰好插在中间</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">enemyHealth[enemyId] </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> enemyHealth[enemyId] </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> damage2;  </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 读到 50 → 写 30</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 线程 A 最后写入 30，覆盖了线程 B 的结果</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p>这就是典型的 <strong>last-write-wins</strong> ——线程 A 看到 50、算出差 20 要写 30；线程 B 同步地从 50 开始算、算出 30、写入 30。两个攻击者只造成了一次伤害的效果。</p><h2 id="二、两阶段模式" tabindex="-1">二、两阶段模式 <a class="header-anchor" href="#二、两阶段模式" aria-label="Permalink to &quot;二、两阶段模式&quot;">​</a></h2><p>解决方案是把每个系统的执行分为两个阶段：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>并行段（Parallel.For）</span></span>
<span class="line"><span>  → 只读组件数据（position/range/stats...）</span></span>
<span class="line"><span>  → 计算结果收集到 ConcurrentBag&lt;(enemyId, damage)&gt;</span></span>
<span class="line"><span>  → 禁止写 EnemyHealth / PlayerHealth / ActiveEnemyIds / EventBus</span></span>
<span class="line"><span></span></span>
<span class="line"><span>串行段（帧末统一结算）</span></span>
<span class="line"><span>  → 从 ConcurrentBag 取出所有事件，串行执行 enemyHealth -= damage</span></span>
<span class="line"><span>  → QueueEnemyDeath → ResolveEnemiesKilledThisFrame() 统一销毁实体</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p>关键原则：</p><ol><li><p><strong>damage queue 存 raw value，不存 derived value</strong>。存 <code>(enemyId, 20)</code> 而不是 <code>(enemyId, 30)</code>。多个攻击者对同一敌人的伤害可以通过加法累加——<code>enemyHealth -= damage1; enemyHealth -= damage2;</code> 结果正确，而 <code>enemyHealth = clampedValue1; enemyHealth = clampedValue2;</code> 会丢伤害。</p></li><li><p><strong>帧末统一做死亡结算</strong>。系统只负责说&quot;这个敌人该死了&quot;，GameManager 负责说&quot;什么时候销毁、按什么顺序销毁、销毁后触发什么奖励结算&quot;。这避免了 A 系统在 B 系统还在遍历敌人列表时把某个实体销毁，导致 B 系统的迭代器出错。</p></li><li><p><strong>EnemyAI 的两阶段</strong>。行为树评估（BT 解析、action 选优）在并行段，动作执行（<code>EventBus.Publish</code>、写攻击相关数据）在串行段。因为 EventBus 的 Publish 可能触发其他系统的回调，如果并行执行会导致级联的竞争条件。</p></li></ol><p>调用的整体链路：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GameManager.Run()</span></span>
<span class="line"><span>  → BeginFrame()（重置 queues）</span></span>
<span class="line"><span>  → 各系统 Update()（只 queue，不 resolve）</span></span>
<span class="line"><span>  → ResolveEnemiesKilledThisFrame()（统一结算，死亡队列自清空）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><h2 id="三、具体踩坑案例" tabindex="-1">三、具体踩坑案例 <a class="header-anchor" href="#三、具体踩坑案例" aria-label="Permalink to &quot;三、具体踩坑案例&quot;">​</a></h2><h3 id="案例-1-getallactiveenemyids-返回内部引用" tabindex="-1">案例 1：GetAllActiveEnemyIds 返回内部引用 <a class="header-anchor" href="#案例-1-getallactiveenemyids-返回内部引用" aria-label="Permalink to &quot;案例 1：GetAllActiveEnemyIds 返回内部引用&quot;">​</a></h3><div class="language-csharp vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">csharp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 错误版本</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">public</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> List</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">int</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">GetAllActiveEnemyIds</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">() </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ActiveEnemyIds;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 修复版本</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">public</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> IReadOnlyList</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">int</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">GetAllActiveEnemyIds</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">()</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    =&gt;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> new</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> List</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">int</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;(ActiveEnemyIds);</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>返回内部 <code>List&lt;int&gt;</code> 引用意味着调用方拿到的是一个可变对象。如果某个系统在遍历这个列表的过程中，另一个系统（比如 WaveSpawning）在 <code>BeginFrame</code> 时添加了新敌人，<code>ActiveEnemyIds</code> 扩容，持有旧引用的系统可能访问到已被 GC 回收的内存区域。</p><p>改成返回<strong>副本</strong>解决了问题，代价是每帧多分配一个 List。对于最多 10K 实体的场景这个开销可接受。如果是更极端的性能要求场景，可以考虑双缓冲——写入 <code>_pending</code>、交换指针、读取 <code>_current</code>。</p><h3 id="案例-2-float-和-bool-的并行写入没有任何保护" tabindex="-1">案例 2：float[] 和 bool[] 的并行写入没有任何保护 <a class="header-anchor" href="#案例-2-float-和-bool-的并行写入没有任何保护" aria-label="Permalink to &quot;案例 2：float[] 和 bool[] 的并行写入没有任何保护&quot;">​</a></h3><p>C# 的 <code>float[]</code> 读写不是原子操作。在 x86 上，对齐的 <code>float</code>（4 字节）读写通常不会出现 tearing，但这个假设不是语言保证的。正确的做法是<strong>永远不要在并行段写共享 float[]</strong>，即使是看起来&quot;无害&quot;的 <code>enemyHealth[i] -= damage</code>。</p><p>本项目在把所有 damage 写入改为 ConcurrentBag 收集、串行 apply 之后，再也没有出现过伤害丢失的 bug。</p><h3 id="案例-3-concurrentbag-和-concurrentdictionary-的选择" tabindex="-1">案例 3：ConcurrentBag 和 ConcurrentDictionary 的选择 <a class="header-anchor" href="#案例-3-concurrentbag-和-concurrentdictionary-的选择" aria-label="Permalink to &quot;案例 3：ConcurrentBag 和 ConcurrentDictionary 的选择&quot;">​</a></h3><p>最开始用了 <code>ConcurrentDictionary&lt;int, float&gt;</code>（enemyId → 累加伤害），后来发现：</p><ul><li>Dictionary 的 key 可能是热的（同一 enemy 被多次命中），内部锁竞争比 Bag 严重</li><li>Bag 只是追加，不需要 key 查找，性能好得多</li></ul><p>改 Bag 后串行段多了一步——需要按 enemyId 把 damage 累加，但因为串行段的 <code>List&lt;(enemyId, damage)&gt;</code> 是单线程处理的，按 enemyId 分组累加是 O(n) 操作，比并行 Dictionary 的锁开销小。</p><h2 id="四、这个模式不只适用于-ecs" tabindex="-1">四、这个模式不只适用于 ECS <a class="header-anchor" href="#四、这个模式不只适用于-ecs" aria-label="Permalink to &quot;四、这个模式不只适用于 ECS&quot;">​</a></h2><p>两阶段模式不限于 ECS，任何需要在多线程/多系统环境下操作共享状态的场景都可以用：</p><ul><li><strong>MVC 框架</strong>：多个 Controller 对同一个 Model 的修改，可以收集事件、帧末统一同步到 Model</li><li><strong>服务端战斗计算</strong>：多个玩家同时攻击一个 Boss，集中收集操作、在帧末统一计算并广播结果</li><li><strong>MonoBehaviour Update 链</strong>：如果有多个 Update 需要修改同一个数据，可以约定&quot;Update 只收集意图，LateUpdate 统一执行&quot;</li></ul><p>核心思想都一样：</p><blockquote><p>把&quot;什么时候写&quot;和&quot;谁来写&quot;分开。并行段只读不写只收集，串行段做真正的写。</p></blockquote><h2 id="参考文献" tabindex="-1">参考文献 <a class="header-anchor" href="#参考文献" aria-label="Permalink to &quot;参考文献&quot;">​</a></h2><ul><li><a href="https://github.com/luoxixuan/battlesystem-ecs" target="_blank" rel="noreferrer">GitHub — BattleSystem-ECS</a>（个人项目，本文相关内容来自此仓库）</li><li>本项目文档 [docs/philosophy.md]</li><li><a href="https://github.com/dotnet/runtime/blob/main/src/libraries/System.Collections.Concurrent/src/System/Collections/Concurrent/ConcurrentBag.cs" target="_blank" rel="noreferrer">C# 中 ConcurrentBag 的内部实现</a></li></ul>`,35)])])}const u=s(l,[["render",t]]);export{k as __pageData,u as default};
